import{_ as r,o as d,c as a,a0 as o}from"./chunks/framework.DV6pVIgV.js";const c=JSON.parse('{"title":"AI 與機器學習","description":"","frontmatter":{},"headers":[],"relativePath":"clf-c02/12.md","filePath":"clf-c02/12.md","lastUpdated":1783683951000}'),e={name:"clf-c02/12.md"};function n(s,t,g,l,i,h){return d(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="ai-與機器學習" tabindex="-1">AI 與機器學習 <a class="header-anchor" href="#ai-與機器學習" aria-label="Permalink to &quot;AI 與機器學習&quot;">​</a></h1><p>用現成 AI vs 自建模型、生成式 AI。這是 CLF-C02 <strong>新增</strong>的模組（C01 沒有）。</p><h2 id="先備知識" tabindex="-1">先備知識 <a class="header-anchor" href="#先備知識" aria-label="Permalink to &quot;先備知識&quot;">​</a></h2><ul><li><p><strong>機器學習（Machine Learning）</strong></p><ul><li><a href="https://aws.amazon.com/tw/what-is/machine-learning/" target="_blank" rel="noreferrer">什麼是機器學習？（AWS）</a></li></ul></li><li><p><strong>深度學習（Deep Learning）</strong></p><ul><li><a href="https://aws.amazon.com/what-is/deep-learning/" target="_blank" rel="noreferrer">什麼是深度學習？（AWS）</a></li></ul></li></ul><h2 id="ai-ml-on-aws-用現成的-vs-自己建" tabindex="-1">AI/ML on AWS：用現成的 vs 自己建 <a class="header-anchor" href="#ai-ml-on-aws-用現成的-vs-自己建" aria-label="Permalink to &quot;AI/ML on AWS：用現成的 vs 自己建&quot;">​</a></h2><p>AWS 的 AI/ML 服務分成兩大類，：</p><table tabindex="0"><thead><tr><th></th><th>現成 AI 服務</th><th>自己建模型的平台</th></tr></thead><tbody><tr><td>是什麼</td><td>AWS <strong>預先訓練好</strong>的 AI 能力，呼叫 API 就能用</td><td>讓你<strong>從頭建立、訓練、部署</strong>自己的模型</td></tr><tr><td>需要 ML 知識嗎</td><td><strong>不用</strong>，會呼叫 API 即可</td><td>需要資料科學 / ML 專業</td></tr><tr><td>代表服務</td><td>Rekognition、Comprehend、Polly…</td><td><strong>Amazon SageMaker AI</strong></td></tr><tr><td>類比</td><td><strong>即食調理包</strong>，拆封即用</td><td><strong>從食材開始自己下廚</strong>，完全客製</td></tr></tbody></table><p>「不想碰 ML、直接要結果」→ 用<strong>現成 AI 服務</strong></p><p>「要用自己的資料訓練專屬模型」→ <strong>SageMaker AI</strong>。</p><h2 id="aws-現成-ai-服務" tabindex="-1">AWS 現成 AI 服務 <a class="header-anchor" href="#aws-現成-ai-服務" aria-label="Permalink to &quot;AWS 現成 AI 服務&quot;">​</a></h2><p>這些都是「丟資料進去、拿結果出來」的預訓練服務，記住每個處理哪種資料即可：</p><table tabindex="0"><thead><tr><th>服務</th><th>處理什麼</th><th>功能重點</th></tr></thead><tbody><tr><td><strong>Rekognition</strong></td><td>影像 / 影片</td><td>物件與場景偵測、人臉分析與比對（可做身分驗證）、影像 OCR、不當內容審核</td></tr><tr><td><strong>Comprehend</strong></td><td>文字（NLP）</td><td>情感分析、抽取實體 / 關鍵字 / PII 個資</td></tr><tr><td><strong>Textract</strong></td><td>文件 / 表單</td><td>不只 OCR——還能解析鍵值對與表格結構（發票、申請表自動化）</td></tr><tr><td><strong>Transcribe</strong></td><td>語音 → 文字</td><td>多語言、講者辨識（diarization）、自動 PII 遮蔽；Transcribe Medical 處理醫療語音</td></tr><tr><td><strong>Translate</strong></td><td>語言</td><td>神經機器翻譯，支援即時 / 批次；可設自訂術語表</td></tr><tr><td><strong>Polly</strong></td><td>文字 → 語音</td><td>擬真 / 神經語音；可用 SSML 控語調；適合 IVR、有聲內容</td></tr><tr><td><strong>Lex</strong></td><td>對話</td><td>打造語音 / 文字聊天機器人（intent / slot；Alexa 同款技術）；常接 Lambda 與 Connect</td></tr><tr><td><strong>Personalize</strong></td><td>推薦</td><td>即時個人化推薦（Amazon.com 同源技術）</td></tr><tr><td><strong>Kendra</strong></td><td>企業文件搜尋</td><td>ML 智慧搜尋，用自然語言問內部文件；常當 RAG 資料源</td></tr><tr><td><strong>Fraud Detector</strong></td><td>詐騙偵測</td><td>託管詐騙 / 假帳號偵測模型</td></tr></tbody></table><p>服務名稱幾乎都與其功能有關——Transcribe（謄寫）、Translate（翻譯）、Polly 會說話（像鸚鵡 Polly）、Textract = Text + extract（抽文字）、Comprehend（理解文字）。</p><h2 id="生成式-ai-on-aws" tabindex="-1">生成式 AI on AWS <a class="header-anchor" href="#生成式-ai-on-aws" aria-label="Permalink to &quot;生成式 AI on AWS&quot;">​</a></h2><p>前面的 AI 服務多半是「判斷 / 分類」（這是不是貓？情緒正負？）；生成式 AI 會「創造新內容」——寫文章、生成圖片、寫程式碼。它背後是<strong>基礎模型（Foundation Model, FM）</strong>：用海量資料訓練出的「博學通才」，可以直接呼叫、也可以再微調。</p><h3 id="aws-的生成式-ai-三層" tabindex="-1">AWS 的生成式 AI 三層 <a class="header-anchor" href="#aws-的生成式-ai-三層" aria-label="Permalink to &quot;AWS 的生成式 AI 三層&quot;">​</a></h3><table tabindex="0"><thead><tr><th>層級</th><th>服務</th><th>做什麼</th></tr></thead><tbody><tr><td>應用層（現成 AI 助理）</td><td><strong>Amazon Q</strong></td><td>AWS 的生成式 AI 助理：Q Business（企業知識問答、提升生產力）、Q Developer（寫程式 / 雲端開發助手）</td></tr><tr><td>模型層（建生成式 AI 應用）</td><td><strong>Amazon Bedrock</strong></td><td>透過 API 使用現成基礎模型（含 Anthropic Claude、Amazon Nova、Meta 等）打造自己的應用——用模型，不訓練模型</td></tr><tr><td>基礎建設層（訓練自己的模型）</td><td><strong>Amazon SageMaker AI</strong></td><td>要從頭訓練 / 客製自己的模型時用</td></tr></tbody></table><h3 id="amazon-bedrock-詳解" tabindex="-1">Amazon Bedrock 詳解 <a class="header-anchor" href="#amazon-bedrock-詳解" aria-label="Permalink to &quot;Amazon Bedrock 詳解&quot;">​</a></h3><p>Bedrock 是<strong>完全託管、無伺服器</strong>的服務，透過單一 API 呼叫多家基礎模型（Anthropic Claude、Amazon Titan / Nova、Meta Llama、Mistral、Cohere 等），不用管任何基礎設施。除了直接呼叫模型，還有四個功能：</p><table tabindex="0"><thead><tr><th>功能</th><th>做什麼</th></tr></thead><tbody><tr><td><strong>Guardrails（護欄）</strong></td><td>負責任 AI 安全層——過濾有害內容、PII 個資遮蔽、防提示攻擊（prompt injection）、幻覺偵測</td></tr><tr><td><strong>Knowledge Bases（知識庫）</strong></td><td>託管 RAG：把基礎模型接上<strong>你自己的資料</strong>（公司文件、S3 等），讓回答有依據</td></tr><tr><td><strong>Agents（代理）</strong></td><td>讓模型自動呼叫 API / 工具，執行多步驟任務</td></tr><tr><td><strong>模型客製</strong></td><td>用自己的資料微調（fine-tuning）現有基礎模型；Model Evaluation 協助比較與選模型</td></tr></tbody></table><p>Bedrock = <strong>用</strong>現成模型（不建模型），還能「接你的資料（Knowledge Bases）＋加安全護欄（Guardrails）＋讓模型自己辦事（Agents）」。</p><h3 id="amazon-q" tabindex="-1">Amazon Q <a class="header-anchor" href="#amazon-q" aria-label="Permalink to &quot;Amazon Q&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>說明</th></tr></thead><tbody><tr><td><strong>Q Business</strong></td><td>企業知識助理，連接公司 40＋ 種資料源（SharePoint、Confluence、S3 等），做問答、摘要、內容生成，提升員工生產力</td></tr><tr><td><strong>Q Developer</strong></td><td>開發 / AWS 助手（整合 IDE、CLI、主控台），程式生成與除錯、AWS 資源問答</td></tr></tbody></table><h3 id="bedrock-vs-sagemaker" tabindex="-1">Bedrock vs SageMaker <a class="header-anchor" href="#bedrock-vs-sagemaker" aria-label="Permalink to &quot;Bedrock vs SageMaker&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>Amazon Bedrock</th><th>Amazon SageMaker AI</th></tr></thead><tbody><tr><td>你做什麼</td><td>用現成的基礎模型（推論）</td><td>建立並訓練自己的模型</td></tr><tr><td>何時選</td><td>想快速把生成式 AI 整合進應用、不想自己訓練</td><td>要用自己的資料訓練專屬模型</td></tr><tr><td>類比</td><td>租一位現成大廚幫你做菜（你只點菜）</td><td>自己從食材開始下廚</td></tr></tbody></table><blockquote><p>「快速用現成基礎模型 / 生成式 AI」→ <strong>Bedrock</strong>；「訓練客製模型」→ <strong>SageMaker AI</strong>。精準的數值預測 / 分類迴歸是傳統 ML 任務，選 <strong>SageMaker AI</strong>，不是 Bedrock。</p></blockquote><h2 id="重點整理" tabindex="-1">重點整理 <a class="header-anchor" href="#重點整理" aria-label="Permalink to &quot;重點整理&quot;">​</a></h2><ul><li><strong>分類</strong>：<strong>現成 AI 服務</strong>（API 即用、免 ML 知識）vs <strong>SageMaker AI</strong>（自己建 / 訓練模型）</li><li><strong>現成 AI 服務</strong>：Rekognition（影像）、Comprehend（文字 NLP）、Textract（文件 / 表單結構，<strong>不只 OCR</strong>）、Transcribe（語音轉文字）、Polly（文字轉語音）、Translate（翻譯）、Lex（對話機器人）、Personalize（推薦）；<strong>Kendra</strong>（企業文件智慧搜尋）、<strong>Fraud Detector</strong>（詐騙偵測）</li><li><strong>生成式 AI 三層</strong>：<strong>Amazon Q</strong>（Q Business 企業知識、Q Developer 開發助手）→ <strong>Bedrock</strong>（用現成基礎模型；加值：Guardrails / Knowledge Bases / Agents）→ <strong>SageMaker AI</strong>（建 / 訓練自己的模型）</li></ul><table tabindex="0"><thead><tr><th>情境需求</th><th>答案</th></tr></thead><tbody><tr><td>不想碰 ML、直接要 AI 結果</td><td><strong>現成 AI 服務</strong>（Rekognition / Comprehend / Textract…）</td></tr><tr><td>用自己的資料訓練專屬模型</td><td><strong>SageMaker AI</strong></td></tr><tr><td>辨識影像 / 影片裡的物件、人臉</td><td><strong>Rekognition</strong></td></tr><tr><td>分析文字情感 / 抽關鍵字</td><td><strong>Comprehend</strong></td></tr><tr><td>從掃描文件 / 表單抽出文字與表格結構</td><td><strong>Textract</strong></td></tr><tr><td>語音轉文字</td><td><strong>Transcribe</strong></td></tr><tr><td>文字轉語音</td><td><strong>Polly</strong></td></tr><tr><td>打造聊天機器人</td><td><strong>Lex</strong></td></tr><tr><td>個人化推薦</td><td><strong>Personalize</strong></td></tr><tr><td>用自然語言搜尋企業內部文件</td><td><strong>Kendra</strong></td></tr><tr><td>偵測詐騙 / 假帳號</td><td><strong>Fraud Detector</strong></td></tr><tr><td>快速用現成基礎模型建生成式 AI 應用</td><td><strong>Bedrock</strong></td></tr><tr><td>企業員工知識問答 / 提升生產力</td><td><strong>Amazon Q Business</strong></td></tr><tr><td>AI 程式生成 / 開發助手（IDE）</td><td><strong>Amazon Q Developer</strong></td></tr></tbody></table>',29)])])}const b=r(e,[["render",n]]);export{c as __pageData,b as default};
